@app.route('/api/users/<int:user_id>', methods=['PUT'])
def update_user(user_id):
    user = User.query.get(user_id)
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    # Get the current admin user
    current_admin = Admin.query.filter_by(username=current_user.username).first()
    
    # Check if the current admin has permission to update this user
    if not current_admin or not current_admin.has_permission('update_users'):
        return jsonify({'error': 'You do not have permission to update users'}), 403
    
    # Get the updated user details from the request body
    data = request.get_json()
    email = data.get('email')
    username = data.get('username')
    role = data.get('role')
    account_status = data.get('account_status')
    subscription_tier = data.get('subscription_tier')
    
    # Update the user record with the new details
    user.email = email
    user.username = username
    user.role = role
    user.account_status = account_status
    user.subscription_tier = subscription_tier
    
    db.session.commit()
    
